using UnityEngine;
using FL.Gameplay.Modules.BigWorld;
using System.Reflection;
public class Script
{
    public static object Main()
    {
        var controllers = Object.FindObjectsOfType<BigWorldNpcController>();
        var sb = new System.Text.StringBuilder();
        sb.AppendLine("NPC count: " + controllers.Length);
        for (int i = 0; i < System.Math.Min(controllers.Length, 3); i++)
        {
            var c = controllers[i];
            if (c.TransformComp == null) { sb.AppendLine("NPC["+i+"] no TransformComp"); continue; }
            var field = typeof(FL.Gameplay.Modules.BigWorld.BigWorldNpcTransformComp).GetField("_snapshotQueue", BindingFlags.NonPublic | BindingFlags.Instance);
            if (field == null) { sb.AppendLine("NPC["+i+"] cannot find _snapshotQueue field"); continue; }
            var queue = field.GetValue(c.TransformComp);
            if (queue == null) { sb.AppendLine("NPC["+i+"] _snapshotQueue is null"); continue; }
            var queueType = queue.GetType();
            var countProp = queueType.GetProperty("SnapshotCount");
            var posProp = queueType.GetProperty("Position");
            int count = countProp != null ? (int)countProp.GetValue(queue) : -1;
            var pos = posProp != null ? posProp.GetValue(queue) : null;
            var prevPos = c.TransformComp.PreviousPosition;
            var transPos = c.GetTransform() != null ? c.GetTransform().position : Vector3.zero;
            sb.AppendLine("NPC["+i+"] snapshotCount=" + count + " queuePos=" + pos + " prevPos=" + prevPos.ToString("F2") + " transPos=" + transPos.ToString("F2") + " speed=" + c.MoveComp.CurrentSpeed.ToString("F3"));
        }
        return sb.ToString();
    }
}
